                best = ((dx, dy), val)
        return [best[0][0], best[0][1]]

    best_move = (0, 0)
    best_val = -10**18

    for dx, dy in dirs:
        nx, ny = sx + dx, sy + dy
        if not valid(nx, ny):
            continue
        my_best = 10**9
        opp_best = 10**9
        gap_best = -10**9
        for rx, ry in resources:
            md = cheb(nx, ny, rx, ry)
            od = cheb(ox, oy, rx, ry)
            if md < my_best:
                my_best = md
            if od < opp_best:
                opp_best = od
            gap = od - md
            if gap > gap_best:
                gap_best = gap
        # Prefer reducing own distance; also prefer moving toward resources where we are closer than opponent.
        val = (-my_best) + 1.5 * gap_best
        # Small tie-breaker: avoid getting closer than opponent without improving.
        val += 0.05 * cheb(nx, ny, ox, oy)
        if val > best_val:
            best_val = val
            best_move = (dx, dy)

    return [best_move[0], best_move[1]]
